import React, { useState, useRef } from 'react';
import './VideoUpload.css';

const VideoUpload = ({ onVideoSelect }) => {
  const [error, setError] = useState(null);
  const videoInput = useRef(null);

  const checkTimeRestriction = () => {
    const currentHour = new Date().getHours();
    return currentHour >= 14 && currentHour < 19;
  };

  const handleVideoSelect = async (e) => {
    const file = e.target.files[0];
    setError(null);

    if (!checkTimeRestriction()) {
      setError('Videos can only be uploaded between 2 PM and 7 PM');
      return;
    }

    if (!file) return;

    // Check file size (50MB = 52428800 bytes)
    if (file.size > 52428800) {
      setError('Video size should not exceed 50MB');
      return;
    }

    // Check video duration
    const video = document.createElement('video');
    video.preload = 'metadata';

    video.onloadedmetadata = function() {
      window.URL.revokeObjectURL(video.src);
      if (video.duration > 120) { // 2 minutes = 120 seconds
        setError('Video length should not exceed 2 minutes');
        return;
      }
      onVideoSelect(file);
    };

    video.src = URL.createObjectURL(file);
  };

  return (
    <div className="video-upload-container">
      <input
        type="file"
        ref={videoInput}
        accept="video/*"
        onChange={handleVideoSelect}
        className="video-input"
      />
      {error && <div className="error-message">{error}</div>}
    </div>
  );
};

export default VideoUpload;
